blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie zobaczysz, które czasowniki <strong>zwykle nie tworzą strony biernej</strong> i dlaczego. Dzięki temu łatwiej unikniesz nienaturalnych albo po prostu błędnych zdań.",
    "rules": [
        {
            "label": "Nieprzechodnie",
            "color": "rose",
            "text": "<strong>Czasowniki nieprzechodnie</strong> nie mają dopełnienia bliższego, więc zwykle nie tworzą strony biernej.",
            "example": "He arrived. ✅ (nie: He was arrived. ❌)"
        },
        {
            "label": "Czasowniki statyczne",
            "color": "amber",
            "text": "Wiele <strong>czasowników statycznych</strong> opisuje stan, posiadanie albo relację, a nie działanie skierowane na obiekt.",
            "example": "I have a car. ✅ (nie: A car is had by me. ❌)"
        },
        {
            "label": "Zwrotne i wzajemne",
            "color": "blue",
            "text": "Konstrukcje <strong>reflexive</strong> i <strong>reciprocal</strong> zwykle nie tworzą naturalnej strony biernej.",
            "example": "She washed herself. ✅ (nie: Herself was washed. ❌)"
        }
    ]
}

{
    "title": "1. Czasowniki nieprzechodnie",
    "intro": "Jeśli czasownik nie ma dopełnienia bliższego, zwykle <strong>nie ma czego przenieść</strong> na pozycję podmiotu w stronie biernej.",
    "items": [
        {
            "label": "arrive",
            "title": "arrive",
            "subtitle": "He arrived late. ✅ (nie: He was arrived. ❌)"
        },
        {
            "label": "go",
            "title": "go",
            "subtitle": "They went home. ✅ (nie: Home was gone. ❌)"
        },
        {
            "label": "come",
            "title": "come",
            "subtitle": "She came early. ✅ (bez strony biernej)"
        },
        {
            "label": "sleep",
            "title": "sleep",
            "subtitle": "He slept well. ✅ (bez strony biernej)"
        },
        {
            "label": "die",
            "title": "die",
            "subtitle": "The king died. ✅ (bez strony biernej)"
        },
        {
            "label": "happen",
            "title": "happen",
            "subtitle": "It happened yesterday. ✅ (bez strony biernej)"
        },
        {
            "label": "exist",
            "title": "exist",
            "subtitle": "Such problems exist. ✅ (bez strony biernej)"
        },
        {
            "label": "appear",
            "title": "appear",
            "subtitle": "A strange light appeared. ✅ (bez strony biernej)"
        }
    ]
}

{
    "title": "2. Czasowniki statyczne",
    "sections": [
        {
            "label": "Posiadanie",
            "color": "rose",
            "description": "Czasowniki wyrażające <strong>posiadanie</strong> zwykle nie tworzą naturalnej strony biernej.",
            "examples": [
                {
                    "en": "I have a car. ✅",
                    "ua": "Nie tworzymy z tego naturalnego zdania biernego."
                },
                {
                    "en": "She owns a house. ✅",
                    "ua": "Zdanie bierne brzmiałoby sztucznie."
                },
                {
                    "en": "They possess great wealth. ✅",
                    "ua": "Tutaj liczy się stan posiadania, a nie działanie."
                }
            ]
        },
        {
            "label": "Dopasowanie i miara",
            "color": "amber",
            "description": "Niektóre czasowniki opisują <strong>dopasowanie</strong>, <strong>wagę</strong> albo <strong>wielkość</strong>, a nie czynność wykonywaną na obiekcie.",
            "examples": [
                {
                    "en": "The dress fits her. ✅",
                    "ua": "Nie: „She is fitted by the dress”."
                },
                {
                    "en": "This shirt suits you. ✅",
                    "ua": "To opis dopasowania, nie działania."
                },
                {
                    "en": "The bag weighs 5 kg. ✅",
                    "ua": "Czasownik oznacza cechę, nie czynność."
                }
            ]
        },
        {
            "label": "Zawartość i pojemność",
            "color": "blue",
            "description": "Czasowniki takie jak <strong>contain</strong> albo <strong>hold</strong> także częściej opisują stan niż działanie.",
            "examples": [
                {
                    "en": "The hall holds 500 people. ✅",
                    "ua": "Mówimy o pojemności sali."
                },
                {
                    "en": "The bottle contains water. ✅",
                    "ua": "To informacja o zawartości."
                },
                {
                    "en": "The box includes instructions. ✅",
                    "ua": "Tu również nie chodzi o typowe działanie bierne."
                }
            ]
        },
        {
            "label": "Podobieństwo i brak",
            "color": "emerald",
            "description": "Czasowniki opisujące <strong>podobieństwo</strong>, <strong>równość</strong> albo <strong>brak</strong> też zwykle nie tworzą strony biernej.",
            "examples": [
                {
                    "en": "Tom resembles his father. ✅",
                    "ua": "Nie mówimy: „His father is resembled by Tom”."
                },
                {
                    "en": "This equals that. ✅",
                    "ua": "To relacja, nie działanie."
                },
                {
                    "en": "They lack experience. ✅",
                    "ua": "To opis braku, a nie czynności."
                }
            ]
        }
    ]
}

{
    "title": "3. Czasowniki przechodnie i nieprzechodnie",
    "intro": "Strona bierna powstaje głównie z <strong>czasowników przechodnich</strong>, czyli takich, które mają dopełnienie bliższe.",
    "rows": [
        {
            "en": "Transitive: They wrote a letter.",
            "ua": "Napisali list.",
            "note": "→ Passive: A letter was written. ✅"
        },
        {
            "en": "Intransitive: He arrived late.",
            "ua": "Przyjechał późno.",
            "note": "→ Strona bierna: ❌"
        },
        {
            "en": "Transitive: She opened the door.",
            "ua": "Otworzyła drzwi.",
            "note": "→ Passive: The door was opened. ✅"
        },
        {
            "en": "Intransitive: The door opened.",
            "ua": "Drzwi się otworzyły.",
            "note": "→ Strona bierna: ❌"
        }
    ],
    "warning": "📌 Zawsze sprawdź, czy czasownik rzeczywiście ma dopełnienie bliższe."
}

{
    "title": "4. Czasowniki zwrotne i wzajemne",
    "sections": [
        {
            "label": "Konstrukcje zwrotne",
            "color": "rose",
            "description": "Gdy podmiot i dopełnienie oznaczają <strong>tę samą osobę</strong>, strona bierna zwykle nie brzmi naturalnie.",
            "examples": [
                {
                    "en": "She washed herself. ✅",
                    "ua": "Nie tworzymy z tego naturalnego zdania biernego."
                },
                {
                    "en": "He hurt himself. ✅",
                    "ua": "To działanie skierowane na samego siebie."
                },
                {
                    "en": "They introduced themselves. ✅",
                    "ua": "Takie konstrukcje zostawiamy w stronie czynnej."
                }
            ]
        },
        {
            "label": "Konstrukcje wzajemne",
            "color": "blue",
            "description": "To samo dotyczy działań <strong>wzajemnych</strong>, gdy dwie strony robią coś sobie nawzajem.",
            "examples": [
                {
                    "en": "They love each other. ✅",
                    "ua": "Nie używamy tu strony biernej."
                },
                {
                    "en": "We helped each other. ✅",
                    "ua": "To relacja wzajemna, nie bierna."
                },
                {
                    "en": "They met each other. ✅",
                    "ua": "Najnaturalniejsza jest strona czynna."
                }
            ]
        }
    ]
}

{
    "title": "5. Inne ograniczenia",
    "intro": "Niektóre konstrukcje formalnie wyglądają podobnie, ale w praktyce nie tworzą naturalnej strony biernej albo wymagają innej przebudowy zdania.",
    "items": [
        {
            "label": "Cognate objects",
            "title": "pokrewne dopełnienie",
            "subtitle": "live a happy life, dream a strange dream: zwykle bez naturalnej strony biernej"
        },
        {
            "label": "Fixed expressions",
            "title": "utarte połączenia",
            "subtitle": "have a look, take a seat: strona czynna brzmi naturalniej"
        },
        {
            "label": "get + adjective",
            "title": "zmiana stanu",
            "subtitle": "get angry, get tired: to nie jest strona bierna"
        },
        {
            "label": "let / allow",
            "title": "przebudowa konstrukcji",
            "subtitle": "Let me go. → I was allowed to go."
        }
    ]
}

{
    "title": "6. Czasowniki o podwójnym użyciu",
    "intro": "Niektóre czasowniki mogą być raz przechodnie, a raz nieprzechodnie. Wszystko zależy od kontekstu.",
    "rows": [
        {
            "en": "run (transitive): They run a business.",
            "ua": "Prowadzą firmę.",
            "note": "→ A business is run by them. ✅"
        },
        {
            "en": "run (intransitive): He runs every day.",
            "ua": "Codziennie biega.",
            "note": "→ Strona bierna: ❌"
        },
        {
            "en": "grow (transitive): They grow vegetables.",
            "ua": "Uprawiają warzywa.",
            "note": "→ Vegetables are grown. ✅"
        },
        {
            "en": "grow (intransitive): Children grow fast.",
            "ua": "Dzieci szybko rosną.",
            "note": "→ Strona bierna: ❌"
        }
    ],
    "warning": "📌 Ten sam czasownik może działać inaczej w różnych zdaniach."
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Tworzenie strony biernej od czasownika nieprzechodniego.",
            "wrong": "The accident was happened yesterday.",
            "right": "✅ The accident happened yesterday."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Strona bierna z czasownikiem statycznym.",
            "wrong": "A nice house is had by her.",
            "right": "✅ She has a nice house."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Strona bierna z konstrukcją zwrotną.",
            "wrong": "Himself was cut by him.",
            "right": "✅ He cut himself."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Pomylenie użycia przechodniego i nieprzechodniego.",
            "wrong": "He was arrived late.",
            "right": "✅ He arrived late."
        }
    ]
}
